```class Solution {
public:
    vector<int> grayCode(int n) {
        vector<int> grayCode(n+1);
        grayCode[0] = 0;
        for (int i = 1; i <= n; i++) {
            int prev = grayCode[i-1];
            grayCode[i] = (prev ^ (1 << (i-1))) & ~(prev >> (i-1));
        }
        return grayCode;
    }
};
```

